// Unpack the supplier list from the LangGraph payload
// Expected: { pr_id, type: 'rfq'|'rfp', rfq_document, suppliers: [{name, contact_name, contact_email}], deadline }
const input = $input.first().json;
const suppliers = input.suppliers ?? [];

return suppliers.map(supplier => ({
  json: {
    pr_id: input.pr_id,
    type: input.type,
    rfq_document: input.rfq_document,
    rfp_document: input.rfp_document ?? null,
    deadline: input.deadline,
    response_webhook: `http://localhost:5678/webhook/supplier-response?pr_id=${input.pr_id}`,
    supplier_name: supplier.name,
    supplier_contact_name: supplier.contact_name,
    supplier_contact_email: supplier.contact_email,
    sent_at: new Date().toISOString()
  }
}));

// Log all outreach records
const items = $input.all();
return items.map(item => ({
  json: {
    pr_id: item.json.pr_id,
    supplier_email: item.json.supplier_contact_email,
    supplier_name: item.json.supplier_name,
    type: item.json.type,
    deadline: item.json.deadline,
    sent_at: item.json.sent_at,
    status: 'sent'
  }
}));

// Placeholder: in production, query your database for open RFQs past deadline
// For MVP, this returns a hardcoded example of an overdue supplier
return [{
  json: {
    pr_id: 'PR-EXAMPLE-001',
    supplier_contact_email: 'supplier@example.com',
    supplier_contact_name: 'Supplier Contact',
    supplier_name: 'Example Supplier GmbH',
    type: 'rfq',
    deadline: '2026-05-10',
    days_overdue: 5
  }
}];
